const timeInfo = await Memento.system.getCurrentTime();
const year = timeInfo.year;
const startDate = `${year}-01-01T00:00:00.000Z`;
const endDate = `${year}-12-31T23:59:59.999Z`;
const updated = await Memento.plugins.store.updateProduct({
  productId: 'product123',
  name: '免作业卡(升级版)',
  description: '可免除两次作业',
  price: 100,
  stock: 5,
  exchangeStart: startDate,
  exchangeEnd: endDate,
  useDuration: 60
});
setResult(updated);

const result = await Memento.plugins.store.redeem({productId: 'product123'});
const msg = result.success ? `兑换成功!剩余积分: ${result.currentPoints}` : `兑换失败: ${result.message}`;
setResult(msg);

// 增加积分
const result1 = await Memento.plugins.store.addPoints({points: 50, reason: '完成任务奖励'});
setResult(result1);

// 扣除积分
const result2 = await Memento.plugins.store.addPoints({points: -20, reason: '购买道具'});
setResult(result2);

let allHistory = [];
let offset = 0;
const count = 50;

while (true) {
  const result = await Memento.plugins.store.getRedeemHistory({offset, count});
  allHistory = allHistory.concat(result.data);

  if (!result.hasMore) break;
  offset += count;
}

setResult(`共加载 ${allHistory.length} 条兑换记录`);

const result = await Memento.plugins.store.useItem({itemId: '1731473170456'});
const msg = result.success ? '使用成功' : `使用失败: ${result.message}`;
setResult(msg);

const product = await Memento.plugins.store.findProductBy({field: 'id', value: 'product123'});
if (product) {
  setResult(`找到商品: ${product.name}，价格: ${product.price}`);
} else {
  setResult('未找到该商品');
}

const product = await Memento.plugins.store.findProductById({id: 'product123'});
if (product) {
  setResult(`商品名称: ${product.name}, 库存: ${product.stock}`);
} else {
  setResult('商品不存在');
}

const products = await Memento.plugins.store.findProductByName({name: '券', fuzzy: true, findAll: true});
const totalStock = products.reduce((sum, p) => sum + p.stock, 0);
setResult(`找到 ${products.length} 个包含'券'的商品，总库存: ${totalStock}`);

const item = await Memento.plugins.store.findUserItemBy({field: 'id', value: 'item123'});
if (item) {
  setResult(`物品: ${item.productName}，剩余次数: ${item.remainingUses}`);
} else {
  setResult('未找到该物品');
}

const item = await Memento.plugins.store.findUserItemById({id: 'item123'});
if (item) {
  setResult(`物品名称: ${item.productName}, 到期时间: ${item.expiresAt}`);
} else {
  setResult('物品不存在');
}
